def output_result(data: Any, json_output: bool = False):
    """Output result in the requested format."""
    if json_output:
        print(json.dumps(data, indent=2, default=str))
    else:
        if isinstance(data, dict):
            for key, value in data.items():
                print(f"  {key}: {value}")
        elif isinstance(data, list):
            for item in data:
                if isinstance(item, dict):
                    for key, value in item.items():
                        print(f"  {key}: {value}")
                    print()
                else:
                    print(f"  {item}")
        else:
            print(data)


def main():
    parser = build_parser()
    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    if args.verbose:
        logging.getLogger().setLevel(logging.DEBUG)

    # Load configuration securely
    try:
        kafka_config = SecureConfigLoader.load_config(args.config_file)
    except (FileNotFoundError, PermissionError, ValueError) as e:
        logger.error("Configuration error: %s", e)
        sys.exit(1)

    safe_config = SecureConfigLoader.sanitize_config_for_logging(kafka_config)
    logger.debug("Using configuration: %s", safe_config)

    # Execute command
    try:
        with KafkaClusterAdmin(kafka_config) as admin:
            if args.command == "list-topics":
                topics = admin.list_topics()
                print(f"\nTopics ({len(topics)}):")
                output_result(topics, args.json_output)

            elif args.command == "describe-topics":
                descriptions = admin.describe_topics(args.topics)
                print("\nTopic Descriptions:")
                output_result(descriptions, args.json_output)

            elif args.command == "create-topic":
                topic_config = parse_key_value_pairs(args.config)
                topic_spec = {
                    "name": args.topic,
                    "num_partitions": args.partitions,
                    "replication_factor": args.replication_factor,
                    "config": topic_config,
                }
                results = admin.create_topics(
                    [topic_spec], validate_only=args.dry_run
                )
                action = "Validation" if args.dry_run else "Creation"
                print(f"\nTopic {action} Results:")
                output_result(results, args.json_output)

            elif args.command == "create-topics-from-file":
                spec_path = args.spec_file
                with open(spec_path, "r") as f:
                    topic_specs = json.load(f)

                if isinstance(topic_specs, dict):
                    topic_specs = [topic_specs]

                results = admin.create_topics(
                    topic_specs, validate_only=args.dry_run
                )
                action = "Validation" if args.dry_run else "Creation"
                print(f"\nBatch Topic {action} Results:")
                output_result(results, args.json_output)

            elif args.command == "delete-topics":
                if not args.force:
                    topics_str = ", ".join(args.topics)
                    confirm = input(
                        f"Are you sure you want to delete topics: {topics_str}? [y/N] "
                    )
                    if confirm.lower() not in ("y", "yes"):
                        print("Aborted.")
                        sys.exit(0)

                results = admin.delete_topics(args.topics)
                print("\nDeletion Results:")
                output_result(results, args.json_output)

            elif args.command == "add-partitions":
                results = admin.add_partitions(
                    {args.topic: args.total_partitions}
                )
                print("\nPartition Results:")
                output_result(results, args.json_output)

            elif args.command == "get-config":
                config = admin.get_topic_config(args.topic)
                print(f"\nConfiguration for topic '{args.topic}':")
                output_result(config, args.json_output)

            elif args.command == "alter-config":
                configs = parse_key_value_pairs(args.config)
                results = admin.alter_topic_config(args.topic, configs)
                print(f"\nConfig Alteration Results for '{args.topic}':")
                output_result(results, args.json_output)

            elif args.command == "describe-cluster":
                metadata = admin.describe_cluster()
                print("\nCluster Information:")
                output_result(metadata, args.json_output)

            else:
                parser.print_help()
                sys.exit(1)

    except KeyboardInterrupt:
        logger.info("Operation cancelled by user.")
        sys.exit(130)
    except KafkaError as e:
        logger.error("Kafka error: %s", e)
        sys.exit(1)
    except Exception as e:
        logger.error("Unexpected error: %s", e, exc_info=args.verbose)
        sys.exit(1)

    print("\nDone.")


if __name__ == "__main__":
    main()